const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || input;

function env(name, fallback = '') {
  try {
    if (typeof $env !== 'undefined' && $env[name]) return $env[name];
  } catch (error) {}
  try {
    if (typeof process !== 'undefined' && process.env && process.env[name]) return process.env[name];
  } catch (error) {}
  return fallback;
}

function headerValue(name) {
  const lower = name.toLowerCase();
  return headers[name] || headers[lower] || headers[name.toUpperCase()] || '';
}

const FIX_KEY = env('GDA_QA_FIX_KEY');
if (FIX_KEY && headerValue('x-gda-fix-key') !== FIX_KEY) {
  return [{ json: { ok: false, statusCode: 403, error: 'Unauthorized fix request. Missing or invalid x-gda-fix-key.' } }];
}

const FIX_MODE = env('GDA_QA_FIX_MODE', 'dry-run');
const N8N_BASE_URL = env('GDA_QA_N8N_BASE_URL', 'https://n8n.csr-llc.tech').replace(/\/$/, '');
const N8N_API_KEY = env('GDA_QA_N8N_API_KEY');

async function parseResponse(response) {
  const text = await response.text();
  try {
    return JSON.parse(text);
  } catch (error) {
    return { rawText: text.slice(0, 4000) };
  }
}

function requireApproved() {
  if (FIX_MODE !== 'enabled') {
    throw new Error('Fix runner is in dry-run mode. Set GDA_QA_FIX_MODE=enabled before write actions.');
  }
  if (body.approved !== true) {
    throw new Error('Write action requires approved=true in the request body.');
  }
}

async function n8nApi(path, options = {}) {
  if (!N8N_API_KEY) throw new Error('GDA_QA_N8N_API_KEY is not set in n8n environment.');
  const response = await fetch(`${N8N_BASE_URL}${path}`, {
    method: options.method || 'GET',
    headers: {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'X-N8N-API-KEY': N8N_API_KEY,
      ...(options.headers || {})
    },
    body: options.body === undefined ? undefined : JSON.stringify(options.body)
  });
  return { status: response.status, ok: response.ok, body: await parseResponse(response) };
}

function extractWebhookPath(urlOrPath) {
  const value = String(urlOrPath || '');
  const webhookMatch = value.match(/\/webhook(?:-test)?\/([^?#]+)/);
  if (webhookMatch) return webhookMatch[1];
  const apiMatch = value.match(/\/api\/([^?#]+)/);
  if (apiMatch) return apiMatch[1];
  return value.replace(/^\//, '');
}

function suggestFix(findings = []) {
  const suggestions = [];
  for (const finding of findings) {
    const url = finding.url || finding.endpoint || finding.text || '';
    const path = extractWebhookPath(url);
    if (String(url).includes('/webhook/')) {
      suggestions.push({
        type: 'react_direct_n8n_call',
        severity: 'high',
        module: finding.module || 'unknown',
        problem: `Browser appears to call n8n directly: ${url}`,
        recommendedFrontendUrl: `/api/${path}`,
        recommendedProxyTarget: `/webhook/${path}`,
        reason: 'Browser code should not call protected n8n webhooks directly because it cannot safely include x-gda-key.'
      });
    } else if (String(url).includes('/api/')) {
      suggestions.push({
        type: 'proxy_route_or_backend_failure',
        severity: 'medium',
        module: finding.module || 'unknown',
        problem: `API route failed or aborted: ${url}`,
        recommendedCheck: `Verify nginx /api/${path} proxy route and n8n /webhook/${path} workflow response.`,
        recommendedProxyTarget: `/webhook/${path}`
      });
    }
  }
  return suggestions;
}

function createProxyFixManifest(findings = []) {
  const suggestions = suggestFix(findings);
  const routes = [];
  for (const suggestion of suggestions) {
    if (!suggestion.recommendedProxyTarget) continue;
    const apiPath = suggestion.recommendedFrontendUrl || `/api/${extractWebhookPath(suggestion.recommendedProxyTarget)}`;
    if (!routes.some((route) => route.apiPath === apiPath)) {
      routes.push({
        apiPath,
        proxyTarget: suggestion.recommendedProxyTarget,
        headerRequired: 'x-gda-key',
        changeType: 'ensure_proxy_route'
      });
    }
  }
  return {
    routes,
    nginxIntent: 'Ensure each /api/<path> route proxies server-side to n8n /webhook/<path> and injects x-gda-key server-side.',
    frontendIntent: 'Replace browser calls to https://n8n.csr-llc.tech/webhook/<path> with relative /api/<path> calls.'
  };
}

async function activateWorkflow(id) {
  requireApproved();
  if (!id) throw new Error('activate_workflow requires workflowId.');
  const result = await n8nApi(`/api/v1/workflows/${encodeURIComponent(id)}/activate`, { method: 'POST' });
  if (!result.ok) throw new Error(`activate workflow failed: HTTP ${result.status} ${JSON.stringify(result.body).slice(0, 500)}`);
  return result.body;
}

async function deactivateWorkflow(id) {
  requireApproved();
  if (!id) throw new Error('deactivate_workflow requires workflowId.');
  const result = await n8nApi(`/api/v1/workflows/${encodeURIComponent(id)}/deactivate`, { method: 'POST' });
  if (!result.ok) throw new Error(`deactivate workflow failed: HTTP ${result.status} ${JSON.stringify(result.body).slice(0, 500)}`);
  return result.body;
}

async function applyN8nWorkflowUpdate(id, workflow) {
  requireApproved();
  if (!id || !workflow) throw new Error('apply_n8n_workflow_update requires workflowId and workflow.');
  const before = await n8nApi(`/api/v1/workflows/${encodeURIComponent(id)}`);
  if (!before.ok) throw new Error(`could not read workflow backup: HTTP ${before.status} ${JSON.stringify(before.body).slice(0, 500)}`);
  const updated = await n8nApi(`/api/v1/workflows/${encodeURIComponent(id)}`, { method: 'PUT', body: workflow });
  if (!updated.ok) throw new Error(`workflow update failed: HTTP ${updated.status} ${JSON.stringify(updated.body).slice(0, 500)}`);
  return {
    updated: updated.body,
    rollback: {
      action: 'rollback_n8n_workflow',
      workflowId: id,
      approved: true,
      backupWorkflow: before.body
    }
  };
}

async function rollbackN8nWorkflow(id, backupWorkflow) {
  requireApproved();
  if (!id || !backupWorkflow) throw new Error('rollback_n8n_workflow requires workflowId and backupWorkflow.');
  const result = await n8nApi(`/api/v1/workflows/${encodeURIComponent(id)}`, { method: 'PUT', body: backupWorkflow });
  if (!result.ok) throw new Error(`rollback failed: HTTP ${result.status} ${JSON.stringify(result.body).slice(0, 500)}`);
  return result.body;
}

async function main() {
  const action = body.action || 'health';
  if (action === 'health') {
    return {
      ok: true,
      agent: 'GDA.qa.fix-runner',
      mode: FIX_MODE,
      writeActionsEnabled: FIX_MODE === 'enabled',
      n8nApiKeyConfigured: Boolean(N8N_API_KEY),
      supportedActions: ['health', 'suggest_fix', 'create_proxy_fix_manifest', 'activate_workflow', 'deactivate_workflow', 'apply_n8n_workflow_update', 'rollback_n8n_workflow']
    };
  }
  if (action === 'suggest_fix') {
    return { ok: true, dryRun: true, suggestions: suggestFix(body.findings || []) };
  }
  if (action === 'create_proxy_fix_manifest') {
    return { ok: true, dryRun: true, manifest: createProxyFixManifest(body.findings || []) };
  }
  if (action === 'activate_workflow') {
    return { ok: true, action, result: await activateWorkflow(body.workflowId) };
  }
  if (action === 'deactivate_workflow') {
    return { ok: true, action, result: await deactivateWorkflow(body.workflowId) };
  }
  if (action === 'apply_n8n_workflow_update') {
    return { ok: true, action, result: await applyN8nWorkflowUpdate(body.workflowId, body.workflow) };
  }
  if (action === 'rollback_n8n_workflow') {
    return { ok: true, action, result: await rollbackN8nWorkflow(body.workflowId, body.backupWorkflow) };
  }
  return { ok: false, statusCode: 400, error: `Unsupported action: ${action}` };
}

try {
  const result = await main();
  return [{ json: result }];
} catch (error) {
  return [{ json: { ok: false, statusCode: 500, error: error.stack || error.message || String(error) } }];
}
